"use client";
import { RadialMenu } from "@/components/ui/radial-menu";
import { Pencil, Trash, Share2, Star } from "lucide-react";

export default function ActionToolbar() {
  return (
    <div className="flex items-center justify-center h-64">
      <RadialMenu
        items={[
          { id: "edit", label: "Edit", icon: <Pencil size={16} />, color: "#6366f1" },
          { id: "delete", label: "Delete", icon: <Trash size={16} />, color: "#ef4444" },
          { id: "share", label: "Share", icon: <Share2 size={16} />, color: "#22c55e" },
          { id: "star", label: "Favourite", icon: <Star size={16} />, color: "#f59e0b" },
        ]}
        radius={90}
      />
    </div>
  );
}

"use client";
import { RadialMenu } from "@/components/ui/radial-menu";
import { Pen, Eraser, Pipette, Crop } from "lucide-react";

export default function DrawingToolPicker() {
