    <div className="flex items-center justify-center h-64">
      <RadialMenu
        items={[
          { id: "pen", label: "Pen", icon: <Pen size={16} />, color: "#6366f1" },
          { id: "eraser", label: "Eraser", icon: <Eraser size={16} />, color: "#a855f7" },
